'use client';

import ProtectedRoute from '@/components/ProtectedRoute';
import Layout from '@/components/Layout';
import { useState, useEffect } from 'react';
import axios from 'axios';

export const dynamic = 'force-dynamic';

export default function AdminProducts() {
  const [products, setProducts] = useState([]);
  const [form, setForm] = useState({ name: '', description: '', price: '', category: '', imageUrl: '' });
  const [editing, setEditing] = useState(null);

  useEffect(() => { fetchProducts(); }, []);

  const fetchProducts = async () => {
    const res = await axios.get('/api/admin/products');
    setProducts(res.data);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (editing) await axios.put(`/api/admin/products?id=${editing}`, form);
    else await axios.post('/api/admin/products', form);
    setForm({ name: '', description: '', price: '', category: '', imageUrl: '' });
    setEditing(null);
    fetchProducts();
  };

  const handleEdit = (p) => { setForm(p); setEditing(p._id); };
  const handleDelete = async (id) => { if (confirm('Delete?')) { await axios.delete(`/api/admin/products?id=${id}`); fetchProducts(); } };

  return (
    <ProtectedRoute>
      <Layout title="Manage Products">
        <div className="p-8">
          <h1 className="text-3xl font-bold mb-6">Manage Products</h1>
          <form onSubmit={handleSubmit} className="bg-white p-4 rounded shadow mb-8">
            <div className="grid grid-cols-2 gap-4">
              <input type="text" placeholder="Name" value={form.name} onChange={e => setForm({...form, name: e.target.value})} className="border p-2" required />
              <input type="text" placeholder="Category" value={form.category} onChange={e => setForm({...form, category: e.target.value})} className="border p-2" required />
              <input type="number" step="0.01" placeholder="Price" value={form.price} onChange={e => setForm({...form, price: e.target.value})} className="border p-2" required />
              <input type="text" placeholder="Image URL" value={form.imageUrl} onChange={e => setForm({...form, imageUrl: e.target.value})} className="border p-2" required />
              <textarea placeholder="Description" value={form.description} onChange={e => setForm({...form, description: e.target.value})} className="border p-2 col-span-2" rows="3" required />
            </div>
            <button type="submit" className="mt-4 bg-blue-600 text-white px-4 py-2 rounded">{editing ? 'Update' : 'Create'}</button>
            {editing && <button type="button" onClick={() => { setEditing(null); setForm({ name: '', description: '', price: '', category: '', imageUrl: '' }); }} className="ml-2 text-gray-500">Cancel</button>}
          </form>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            {products.map(p => (
              <div key={p._id} className="bg-white p-4 rounded shadow flex justify-between">
                <div><h3 className="font-bold">{p.name}</h3><p className="text-sm text-gray-600">${p.price}</p></div>
                <div><button onClick={() => handleEdit(p)} className="text-blue-600 mr-2">Edit</button><button onClick={() => handleDelete(p._id)} className="text-red-600">Delete</button></div>
              </div>
            ))}
          </div>
        </div>
      </Layout>
    </ProtectedRoute>
  );
}